import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

export default defineConfig({
  plugins: [react()],
})

import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Home from './pages/Home';

function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<Home />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;

@import url('https://api.fontshare.com/v2/css?f[]=general-sans@400,500,600,700&display=swap');
@import url('https://fonts.googleapis.com/css2?family=Geist:wght@100..900&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --background: 260 87% 3%;
  --foreground: 40 6% 95%;
  --hero-sub: 40 6% 82%;
}

body {
  background-color: hsl(var(--background));
  color: hsl(var(--foreground));
  font-family: 'Geist Sans', sans-serif;
  margin: 0;
  padding: 0;
  -webkit-font-smoothing: antialiased;
}

/* Liquid Glass Utility */
.liquid-glass {
  background: rgba(255, 255, 255, 0.01);
  background-blend-mode: luminosity;
  backdrop-filter: blur(4px);
  border: none;
  box-shadow: inset 0 1px 1px rgba(255, 255, 255, 0.1);
  position: relative;
  overflow: hidden;
}

.liquid-glass::before {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: inherit;
  padding: 1.4px;
  background: linear-gradient(
    180deg, 
    rgba(255,255,255,0.45) 0%, 
    rgba(255,255,255,0.15) 20%, 
    rgba(255,255,255,0) 40%, 
    rgba(255,255,255,0) 60%, 
    rgba(255,255,255,0.15) 80%, 
    rgba(255,255,255,0.45) 100%
  );
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  pointer-events: none;
}

/* Base button styles to ensure consistency without relying strictly on Tailwind @apply which might fail in some environments */
.hero-secondary-btn {
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(8px);
  color: hsl(var(--foreground));
  transition: all 0.2s ease-in-out;
}

.hero-secondary-btn:hover {
  background: rgba(255, 255, 255, 0.1);
  border-color: rgba(255, 255, 255, 0.2);
  transform: translateY(-1px);
}

/** @type {import('tailwindcss').Config} */
export default {
  content: [
    "./index.html",
    "./src/**/*.{js,ts,jsx,tsx}",
  ],
  theme: {
    extend: {
      colors: {
        background: "hsl(var(--background))",
        foreground: "hsl(var(--foreground))",
        "hero-sub": "hsl(var(--hero-sub))",
      },
      fontFamily: {
        geist: ['"Geist Sans"', 'sans-serif'],
        general: ['"General Sans"', 'sans-serif'],
      },
      animation: {
        'marquee-scroll': 'scroll 20s linear infinite',
      },
      keyframes: {
        scroll: {
          '0%': { transform: 'translateX(0%)' },
          '100%': { transform: 'translateX(-50%)' },
        }
      }
    },
  },
  plugins: [],
}

import React from 'react';
import Navbar from '../components/Navbar';
import HeroVideo from '../components/HeroVideo';
import Marquee from '../components/Marquee';

export default function Home() {
  return (
    <div className="min-h-screen bg-background text-foreground flex flex-col relative overflow-hidden font-geist">
      {/* Background Video Layer */}
      <div className="absolute inset-0 z-0 overflow-hidden w-full h-full">
        <HeroVideo />
      </div>

      {/* Blurred Overlay Shape */}
      <div 
        className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[984px] h-[527px] opacity-90 bg-gray-950 blur-[82px] pointer-events-none z-0 rounded-full"
        aria-hidden="true"
      />

      {/* Foreground Content */}
      <div className="relative z-10 flex flex-col flex-1 overflow-visible">
        <Navbar />

        {/* Main Hero Content */}
        <main className="flex-1 flex flex-col items-center justify-center px-4 text-center mt-[-40px]">
          <h1 className="text-[120px] md:text-[220px] font-normal leading-[1.02] tracking-[-0.024em] font-general mt-8">
            <span className="text-foreground">Power </span>
            <span 
              className="bg-clip-text text-transparent" 
              style={{ 
                backgroundImage: 'linear-gradient(to left, #6366f1, #a855f7, #fcd34d)' 
              }}
            >
              AI
            </span>
          </h1>

          <p className="text-hero-sub text-lg leading-8 max-w-md mt-[9px] opacity-80">
            The most powerful AI ever deployed<br />
            in talent acquisition
          </p>

          <button className="hero-secondary-btn rounded-full px-[29px] py-[24px] mt-[25px] font-medium text-lg">
            Schedule a Consult
          </button>
        </main>

        <Marquee />
      </div>
    </div>
  );
}

import React, { useRef, useEffect, useState } from 'react';

export default function HeroVideo() {
  const videoRef = useRef(null);
  const [opacity, setOpacity] = useState(0);

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    let animationFrameId;

    const updateOpacity = () => {
      if (video.duration > 0) {
        const time = video.currentTime;
        const duration = video.duration;
        const fadeDuration = 0.5;

        if (time < fadeDuration) {
          // Fade in over the first 0.5s
          setOpacity(time / fadeDuration);
        } else if (duration - time < fadeDuration) {
          // Fade out over the last 0.5s
          setOpacity((duration - time) / fadeDuration);
        } else {
          // Fully visible in the middle
          setOpacity(1);
        }
      }
      animationFrameId = requestAnimationFrame(updateOpacity);
    };

    const handlePlay = () => {
      animationFrameId = requestAnimationFrame(updateOpacity);
    };

    const handlePause = () => {
      cancelAnimationFrame(animationFrameId);
    };

    const handleEnded = () => {
      // Immediate reset on end to trigger loop correctly
      setOpacity(0);
      cancelAnimationFrame(animationFrameId);

      // Wait 100ms then replay from 0
      setTimeout(() => {
        if (video) {
          video.currentTime = 0;
          video.play().catch(e => console.error("Auto-play prevented", e));
        }
      }, 100);
    };

    // Attach listeners
    video.addEventListener('play', handlePlay);
    video.addEventListener('pause', handlePause);
    video.addEventListener('ended', handleEnded);

    // Initial check if video is already playing
    if (!video.paused) {
      handlePlay();
    }

    return () => {
      cancelAnimationFrame(animationFrameId);
      video.removeEventListener('play', handlePlay);
      video.removeEventListener('pause', handlePause);
      video.removeEventListener('ended', handleEnded);
    };
  }, []);

  return (
    <video
      ref={videoRef}
      src="https://d8j0ntlcm91z4.cloudfront.net/user_38xzZboKViGWJOttwIXH07lWA1P/hf_20260328_065045_c44942da-53c6-4804-b734-f9e07fc22e08.mp4"
      autoPlay
      muted
      playsInline
      className="w-full h-full object-cover"
      style={{ 
        opacity, 
        // Using inline style for hardware acceleration on opacity changes
        willChange: 'opacity',
        transition: 'none' // Handled strictly by JS for exact precision
      }}
    />
  );
}

import React, { useState } from 'react';
import { Link } from 'react-router-dom';

export default function Navbar() {
  const [logoError, setLogoError] = useState(false);

  const NavItem = ({ children, hasDropdown }) => (
    <button className="flex items-center gap-1.5 text-foreground/90 hover:text-white transition-colors font-medium text-sm">
      {children}
      {hasDropdown && (
        <iconify-icon 
          icon="solar:alt-arrow-down-linear" 
          width="16" 
          height="16"
          class="opacity-70 mt-0.5"
        />
      )}
    </button>
  );

  return (
    <div className="w-full relative">
      <nav className="w-full py-5 px-8 flex items-center justify-between z-20">
        {/* Left: Logo */}
        <Link to="/" className="flex items-center">
          {!logoError ? (
            <img 
              src="src/assets/logo.png" 
              alt="Power AI Logo" 
              className="h-[32px] object-contain"
              onError={() => setLogoError(true)}
            />
          ) : (
            // Fallback sleek logo if src/assets/logo.png is missing
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center shadow-lg">
                <iconify-icon icon="solar:bolt-linear" style={{ color: 'white' }} width="20" />
              </div>
            </div>
          )}
        </Link>

        {/* Center: Links */}
        <div className="hidden md:flex items-center gap-8">
          <NavItem hasDropdown>Features</NavItem>
          <NavItem>Solutions</NavItem>
          <NavItem>Plans</NavItem>
          <NavItem hasDropdown>Learning</NavItem>
        </div>

        {/* Right: CTA */}
        <div className="flex items-center">
          <button className="hero-secondary-btn rounded-full px-4 py-2 text-sm font-medium">
            Sign Up
          </button>
        </div>
      </nav>

      {/* Divider */}
      <div className="w-full h-[1px] bg-gradient-to-r from-transparent via-foreground/20 to-transparent mt-[3px]" />
    </div>
  );
}

import React from 'react';

const brands = [
  { name: 'Vortex', initial: 'V' },
  { name: 'Nimbus', initial: 'N' },
  { name: 'Prysma', initial: 'P' },
  { name: 'Cirrus', initial: 'C' },
  { name: 'Kynder', initial: 'K' },
  { name: 'Halcyn', initial: 'H' },
];

export default function Marquee() {
  // Duplicate array for seamless infinite scroll
  const scrollItems = [...brands, ...brands];

  return (
    <div className="max-w-5xl mx-auto w-full px-8 pb-10 mt-auto flex items-center gap-12 overflow-hidden">

      {/* Left Static Text */}
      <div className="flex-shrink-0 text-foreground/50 text-sm leading-snug">
        Relied on by brands<br />
        across the globe
      </div>

      {/* Right Marquee */}
      <div className="flex-1 relative overflow-hidden [mask-image:linear-gradient(to_right,transparent,black_10%,black_90%,transparent)]">
        <div className="flex w-max animate-marquee-scroll hover:[animation-play-state:paused] items-center gap-16">
          {scrollItems.map((brand, index) => (
            <div key={`${brand.name}-${index}`} className="flex items-center gap-3 group cursor-default">

              <div className="liquid-glass w-6 h-6 rounded-lg flex items-center justify-center shrink-0 transition-transform duration-300 group-hover:scale-110 group-hover:shadow-[0_0_15px_rgba(255,255,255,0.1)]">
                <span className="text-foreground text-xs font-medium opacity-90">
                  {brand.initial}
                </span>
              </div>

              <span className="text-base font-medium text-foreground tracking-wide opacity-80 group-hover:opacity-100 transition-opacity">
                {brand.name}
              </span>

            </div>
          ))}
        </div>
      </div>

    </div>
  );
}

